import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.util.Scanner;

public class PathTraversalFixed {
    private static final String BASE_PATH = "/path/to/allowed/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        File requestedFile = new File(BASE_PATH + fileName);

        if (requestedFile.getAbsolutePath().startsWith(BASE_PATH) && requestedFile.exists()) {
            try (BufferedReader br = new BufferedReader(new FileReader(requestedFile))) {
                String line;
                while ((line = br.readLine()) != null) {
                    System.out.println(line);
                }
            } catch (IOException e) {
                System.err.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.err.println("Invalid file path.");
        }
    }
}

